INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64edda80-84b4-4bac-a049-958ebb6a4a62', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_minor_heal', 'Küçük Şifa', 'Minor Heal', 'Dokunulan bir hedefe 1d8 + Bilgelik değiştiricisi kadar can yeniler.', 'Heals a touched target for 1d8 + Wisdom modifier hit points.', 'Healing', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"healing": "1d8", "range": "touch"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ff1bc5d-f4a4-40ec-b298-85f2dea9a776', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_healing_word', 'Şifa Sözü', 'Healing Word', '15m içindeki bir hedefe 1d4 + Bilgelik değiştiricisi kadar can yenileyen hızlı bir şifa sözü.', 'A swift word of healing that restores 1d4 + Wisdom modifier hit points to a target within 15m.', 'Healing', 5, 75, 1, '{"pr_minor_heal"}', '{"x": 389, "y": -224}', '{"healing": "1d4", "range": "15m"}', '💬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48da03b9-c50e-4d45-8d38-5cf862dc60d2', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_soothing_light', 'Yatıştırıcı Işık', 'Soothing Light', 'Hedefi ışıkla yıkarak 3 tur boyunca 2d6 can yeniler.', 'Bathes the target in light, healing 2d6 HP over 3 turns.', 'Healing', 10, 100, 1, '{"pr_healing_word"}', '{"x": 606, "y": -349}', '{"healing": "2d6", "duration": "3 turns"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3650e189-bb61-4b08-9667-1029c3637d31', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_detect_poison', 'Zehir Sezme', 'Detect Poison', '10m yarıçapındaki zehirlerin ve hastalıkların varlığını ve türünü tespit eder.', 'Detects the presence and nature of poisons and diseases within a 10m radius.', 'Purification', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "10m"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50094688-3d25-4306-83a0-c2c6199a7cac', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_purify_food', 'Yiyecek ve İçecek Arındırma', 'Purify Food and Drink', '2m yarıçapındaki büyülü olmayan yiyecek ve içeceklerdeki tüm hastalıkları ve zehirleri temizler.', 'Removes all diseases and poisons from non-magical food and drink within a 2m radius.', 'Purification', 5, 75, 1, '{"pr_detect_poison"}', '{"x": 289, "y": 344}', '{"range": "2m"}', '🥖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('690d23e1-4788-4a8c-b0b2-a8bbcb517ec6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_lesser_restoration', 'Küçük Arınma', 'Lesser Restoration', 'Dokunulan bir yaratıktaki bir hastalığı veya bir durumu (kör, sağır, felçli veya zehirli) iyileştirir.', 'Cures one disease or one condition (blinded, deafened, paralyzed, or poisoned) on a touched creature.', 'Purification', 10, 100, 1, '{"pr_purify_food"}', '{"x": 449, "y": 536}', '{"range": "touch", "removes": "1 condition"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('294483c6-3dda-4110-9589-ab33d986611a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_shield_of_faith', 'İnanç Kalkanı', 'Shield of Faith', '15m içindeki bir yaratığın etrafında parlayan bir kalkan belirir ve 10 dakika boyunca Zırh Sınıfına +2 bonus sağlar.', 'A shimmering field appears and surrounds a creature within 15m, granting a +2 bonus to AC for 10 minutes.', 'Divine Shield', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"ac_bonus": "+2", "range": "15m", "duration": "10 mins"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0584cc42-be90-4384-aef1-d936d4b95e78', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_sanctuary', 'Sığınak', 'Sanctuary', '10m içindeki bir yaratığı korur. Onu hedef alan herhangi bir düşman Bilgelik kurtarma zarı atmalıdır, aksi takdirde saldırıyı boşa harcar. 1 dakika sürer.', 'Wards a creature within 10m. Any enemy targeting them must succeed on a Wisdom saving throw or lose the attack. Lasts 1 minute.', 'Divine Shield', 5, 75, 1, '{"pr_shield_of_faith"}', '{"x": -289, "y": 344}', '{"range": "10m", "duration": "1 min"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4bae1a32-47af-40c8-a65a-003776b6ed84', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_protection_evil', 'Kötülükten Korunma', 'Protection from Evil', 'Dokunulan yaratığı 10 dakika boyunca sapkınlıklardan, göksellerden, elementallerden, perilerden, iblislerden ve ölümsüzlerden korur. Bu yaratıklar hedefe karşı saldırılarda dezavantajlı olur.', 'Protects a touched creature from aberrations, celestials, elementals, fey, fiends, and undead for 10 minutes. They have disadvantage on attacks against the target.', 'Divine Shield', 10, 100, 1, '{"pr_sanctuary"}', '{"x": -449, "y": 536}', '{"range": "touch", "duration": "10 mins"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34c54766-19d1-4fd1-be15-15fccc0ba5dd', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cure_wounds', 'Yara İyileştirme', 'Cure Wounds', 'Dokunduğunuz bir yaratık 2d8 + büyü yapma yeteneği değiştiriciniz kadar can geri kazanır.', 'A creature you touch regains a number of hit points equal to 2d8 + your spellcasting ability modifier.', 'Healing', 21, 175, 2, '{"pr_soothing_light"}', '{"x": 822, "y": -474}', '{"healing": "2d8", "range": "touch"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae74a9ca-7429-4e60-864d-9e25bb6fb9b1', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_mass_healing_word', 'Toplu Şifa Sözü', 'Mass Healing Word', 'Şifa sözleri haykırdığınızda, 15m içindeki seçtiğiniz en fazla 6 yaratık 1d4 + büyü yapma yeteneği değiştiriciniz kadar can geri kazanır.', 'As you call out words of restoration, up to 6 creatures of your choice within 15m regain 1d4 + your spellcasting ability modifier HP.', 'Healing', 25, 200, 2, '{"pr_cure_wounds"}', '{"x": 1039, "y": -599}', '{"healing": "1d4", "range": "15m", "targets": "6"}', '📣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4cf5a8b7-d66b-46fe-a5a7-076799028429', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_beacon_of_hope', 'Umut Işığı', 'Beacon of Hope', '10m içindeki en fazla 6 yaratığa Bilgelik ve ölüm kurtarma zarlarında avantaj sağlar ve 1 dakika boyunca aldıkları tüm şifayı en üst düzeye çıkarır.', 'Grants up to 6 creatures within 10m advantage on Wisdom saves and death saves, and maximizes any healing they receive for 1 minute.', 'Healing', 30, 250, 2, '{"pr_mass_healing_word"}', '{"x": 1255, "y": -724}', '{"range": "10m", "duration": "1 min", "targets": "6"}', '🌅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('483ce44a-4b3c-44fd-9699-77a9a3c4af49', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_remove_curse', 'Lanet Kaldırma', 'Remove Curse', 'Dokunuşunuzla, bir yaratığı veya nesneyi etkileyen tüm lanetler sona erer.', 'At your touch, all curses affecting one creature or object end.', 'Purification', 21, 175, 2, '{"pr_lesser_restoration"}', '{"x": 610, "y": 727}', '{"range": "touch"}', '🪬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6b632b1-7499-424a-962a-31a0eaf01eb5', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleanse_mind', 'Zihin Temizleme', 'Cleanse Mind', '10m içindeki bir hedeften cazibe, korku ve psişik rahatsızlıkları kaldırarak zihinsel berraklığı geri kazandırır.', 'Removes charm, fear, and psychic afflictions from a target within 10m, restoring mental clarity.', 'Purification', 25, 200, 2, '{"pr_remove_curse"}', '{"x": 771, "y": 919}', '{"range": "10m", "removes": "charm/fear"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf11b66c-148e-4969-808f-3e2fe499fb21', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_dispel_magic', 'Büyü Bozma', 'Dispel Magic', '30m içindeki bir yaratık, nesne veya büyü etkisini seçin. Hedefteki 3. aşama veya daha düşük tüm büyüler sona erer.', 'Choose one creature, object, or magical effect within 30m. Any spell of 3rd tier or lower on the target ends.', 'Purification', 30, 250, 2, '{"pr_cleanse_mind"}', '{"x": 932, "y": 1110}', '{"range": "30m"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('975fac33-f270-43a9-9439-0dcb76467d6e', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_warding_bond', 'Koruyucu Bağ', 'Warding Bond', 'Kendinizi dokunulan bir müttefike bağlar. 15m içinde kaldıkça müttefik +1 ZS, +1 kurtarma zarı ve tüm hasarlara karşı direnç kazanır. Onların aldığı hasarın aynısını siz de alırsınız.', 'Links yourself to a touched ally. While within 15m, the ally gains +1 AC, +1 saving throws, and resistance to all damage. You take the same amount of damage they take.', 'Divine Shield', 21, 175, 2, '{"pr_protection_evil"}', '{"x": -610, "y": 727}', '{"range": "15m", "ac_bonus": "+1"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0825fb80-6146-4cb7-87ba-ff500a8d5f26', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_magic_circle', 'Büyülü Çember', 'Magic Circle', '3m yarıçapında büyülü bir enerji silindiri oluşturur. Seçilen yaratık türleri içeri giremez veya içeridekileri etkileyemez. 1 saat sürer.', 'Creates a 3m radius cylinder of magical energy. Chosen creature types cannot enter or affect targets inside. Lasts 1 hour.', 'Divine Shield', 25, 200, 2, '{"pr_warding_bond"}', '{"x": -771, "y": 919}', '{"radius": "3m", "duration": "1 hour"}', '⭕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8c4c5bc-e84a-406c-aa6e-1f23e3275a62', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_divine_barrier', 'Kutsal Bariyer', 'Divine Barrier', '6m uzunluğunda ve 3m yüksekliğinde parlayan bir ışık duvarı çağırır. Fiziksel mermileri engeller ve 50''ye kadar büyü hasarını emer.', 'Summons a glowing wall of light 6m long and 3m high. It blocks physical projectiles and absorbs up to 50 magical damage.', 'Divine Shield', 30, 250, 2, '{"pr_magic_circle"}', '{"x": -932, "y": 1110}', '{"wall_length": "6m", "absorption": "50 damage"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9025f3be-a0c9-4497-9275-0234b214cee6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleansing_touch', 'Arındırıcı Dokunuş', 'Cleansing Touch', '1d8 can yenileyen ve bir küçük zayıflatmayı veya 1. aşama laneti anında kaldıran güçlü bir dokunuş.', 'A potent touch that heals 1d8 HP and instantly removes one minor debuff or tier 1 curse.', 'Healing, Purification', 25, 250, 2, '{"pr_cure_wounds", "pr_remove_curse"}', '{"x": 173, "y": -99}', '{"healing": "1d8", "range": "touch"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('666b5128-ac23-4389-965e-77d8c691da24', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_radiant_ward', 'Parlak Koruma', 'Radiant Ward', 'Bir hedefi 20 geçici can ile korur. Kalkan kırıldığında bir parlama yayar ve 3m içindeki düşmanları 1 turluğuna kör eder.', 'Shields a target for 20 temporary HP. When the shield breaks, it emits a flash, blinding enemies within 3m for 1 turn.', 'Purification, Divine Shield', 30, 275, 2, '{"pr_cleanse_mind", "pr_magic_circle"}', '{"x": 173, "y": -99}', '{"shield": "20 hp", "blind_radius": "3m"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85bd5378-fb24-4f44-8c7a-3117dea0d8e4', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_greater_heal', 'Büyük Şifa', 'Greater Heal', 'Pozitif enerji dalgası, dokunduğunuz bir yaratığı 4d8 + Bilgelik değiştiricisi kadar canla iyileştirir.', 'A surge of positive energy heals a creature you touch for 4d8 + Wisdom modifier hit points.', 'Healing', 41, 350, 3, '{"pr_beacon_of_hope"}', '{"x": 1472, "y": -849}', '{"healing": "4d8", "range": "touch"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e787a092-95a0-4fef-ae1e-9062d79dc39a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_revivify', 'Hayata Döndürme', 'Revivify', 'Son bir dakika içinde ölmüş bir yaratığa dokunarak onu 1 canla hayata döndürür.', 'Touch a creature that has died within the last minute, returning it to life with 1 hit point.', 'Healing', 45, 400, 3, '{"pr_greater_heal"}', '{"x": 1688, "y": -974}', '{"range": "touch", "revive": "1 hp"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('10291225-11cd-4ac4-9e1c-78ddcf9ed04d', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_healing_aura', 'Şifa Halesi', 'Healing Aura', '10m''lik bir hale yayar. İçerideki müttefikler 1 dakika boyunca turunuzun başında 1d6 can geri kazanır.', 'Emanates a 10m aura. Allies inside regain 1d6 HP at the start of your turn for 1 minute.', 'Healing', 50, 450, 3, '{"pr_revivify"}', '{"x": 1905, "y": -1099}', '{"radius": "10m", "healing": "1d6/turn", "duration": "1 min"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9667bdf6-6da8-4952-a3eb-c9190c1afd5c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_greater_restoration', 'Büyük Arınma', 'Greater Restoration', 'Dokunulan bir yaratığı pozitif enerjiyle doldurarak yorgunluğu azaltır veya bir cazibe, taşlaşma, lanet veya yetenek puanı azalmasını sona erdirir.', 'Imbues a touched creature with positive energy, reducing exhaustion, or ending one charm, petrification, curse, or ability score reduction.', 'Purification', 41, 350, 3, '{"pr_dispel_magic"}', '{"x": 1092, "y": 1302}', '{"range": "touch"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed3e4fe4-1481-4aa7-9794-0d63cea8fb3a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_purifying_flame', 'Arındırıcı Alev', 'Purifying Flame', '20m uzağa kutsal bir ateş topu fırlatır. 4d6 parlak hasar verir ve hedefteki büyü güçlendirmelerini arındırır.', 'Hurls a bolt of holy fire 20m. Deals 4d6 radiant damage and purges magical buffs from the target.', 'Purification', 45, 400, 3, '{"pr_greater_restoration"}', '{"x": 1253, "y": 1493}', '{"damage": "4d6", "range": "20m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7667bea-eb63-4553-96c3-f025abd5862c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aura_of_purity', 'Safiyet Halesi', 'Aura of Purity', '10m''lik bir hale, müttefiklere 10 dakika boyunca kör, cazibeli, sağır, korkmuş, felçli veya zehirli olmaya karşı kurtarma zarlarında avantaj sağlar.', 'A 10m aura that grants allies advantage on saving throws against being blinded, charmed, deafened, frightened, paralyzed, or poisoned for 10 minutes.', 'Purification', 50, 450, 3, '{"pr_purifying_flame"}', '{"x": 1414, "y": 1685}', '{"radius": "10m", "duration": "10 mins"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('17b7f96f-d2b3-4726-9269-037e062b1983', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aura_of_life', 'Yaşam Halesi', 'Aura of Life', '10m''lik bir hale. İçindeki düşman olmayan yaratıklar nekrotik hasara karşı dirence sahip olur ve maksimum canları azaltılamaz.', 'A 10m aura. Non-hostile creatures within have resistance to necrotic damage and their maximum HP cannot be reduced.', 'Divine Shield', 41, 350, 3, '{"pr_divine_barrier"}', '{"x": -1092, "y": 1302}', '{"radius": "10m", "resistance": "necrotic"}', '🌱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e4f96fe-95a4-4f05-95dc-9c0fc8283556', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_death_ward', 'Ölüm Koruması', 'Death Ward', 'Dokunulan yaratık 8 saat boyunca korunur. 0 cana düşeceği ilk seferde bunun yerine 1 cana düşer ve büyü sona erer.', 'Touched creature is protected for 8 hours. The first time it would drop to 0 HP, it drops to 1 HP instead, and the spell ends.', 'Divine Shield', 45, 400, 3, '{"pr_aura_of_life"}', '{"x": -1253, "y": 1493}', '{"range": "touch", "duration": "8 hours"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('baf1e11d-6bf4-4f68-b4b9-ecef10023a49', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_guardian_of_faith', 'İnanç Muhafızı', 'Guardian of Faith', '10m içinde boş bir alanda spektral bir muhafız çağırır. 3m yakınına gelen düşman yaratıklara 20 parlak hasar verir. 8 saat veya 60 hasar verene kadar sürer.', 'Summons a spectral guardian in an unoccupied space within 10m. It deals 20 radiant damage to hostile creatures that move within 3m of it. Lasts 8 hours or until it deals 60 damage.', 'Divine Shield', 50, 450, 3, '{"pr_death_ward"}', '{"x": -1414, "y": 1685}', '{"damage": "20", "duration": "8 hours"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f8dcfe6-9151-4004-8a9e-bcc166fa1af9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_sheltering_light', 'Barındıran Işık', 'Sheltering Light', 'Tur başına 10 geçici can sağlayan ve 1d4 can yenileyen 5m''lik bir bölge. 3 tur sürer.', 'A 5m zone that grants 10 temporary HP per turn and heals 1d4 HP. Lasts 3 turns.', 'Healing, Divine Shield', 45, 450, 3, '{"pr_greater_heal", "pr_aura_of_life"}', '{"x": 173, "y": -99}', '{"radius": "5m", "shield": "10/turn", "duration": "3 turns"}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb834d4b-e666-4d30-abf8-28debb7ab4d9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_panacea', 'Her Derde Deva', 'Panacea', 'Bir hedefi 3d8 canla iyileştirir ve tüm aktif zehirleri, hastalıkları ve lanetleri anında kaldırır.', 'Heals a target for 3d8 HP and removes all active poisons, diseases, and curses instantly.', 'Healing, Purification', 55, 500, 3, '{"pr_healing_aura", "pr_aura_of_purity"}', '{"x": 389, "y": -224}', '{"healing": "3d8", "range": "touch"}', '⚕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d7d9906-99fb-42d8-becf-814f6459a78f', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_heal', 'İyileştirme', 'Heal', '15m içinden bir yaratık seçin. 70 can geri kazanır ve körlük, sağırlık ve hastalıklardan kurtulur.', 'Choose a creature within 15m. It regains 70 hit points and is cured of blindness, deafness, and any diseases.', 'Healing', 61, 600, 4, '{"pr_healing_aura"}', '{"x": 2121, "y": -1224}', '{"healing": "70", "range": "15m"}', '💞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c352839-9b79-4845-a60b-e87b05393333', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_mass_cure_wounds', 'Toplu Yara İyileştirme', 'Mass Cure Wounds', '15m içindeki bir noktadan şifa enerjisi dalgası yayılır. 10m yarıçapındaki en fazla 6 yaratık 3d8 + Bilgelik değiştiricisi kadar can kazanır.', 'A wave of healing energy washes out from a point within 15m. Up to 6 creatures in a 10m radius regain 3d8 + Wisdom modifier hit points.', 'Healing', 65, 700, 4, '{"pr_heal"}', '{"x": 2338, "y": -1349}', '{"healing": "3d8", "radius": "10m", "range": "15m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('568a642a-6674-4ff7-952a-edd9eefb1af9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_resurrection', 'Diriliş', 'Resurrection', 'Dokunulan ölü bir yaratığı, yüzyıldan uzun süredir ölü olmaması şartıyla hayata döndürür. Tüm ölümcül yaraları kapatır ve eksik vücut parçalarını onarır.', 'Restores life to a deceased creature touched, provided it hasn''t been dead for more than a century. Closes all mortal wounds and restores missing body parts.', 'Healing', 70, 800, 4, '{"pr_mass_cure_wounds"}', '{"x": 2554, "y": -1474}', '{"range": "touch"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d493beb2-0893-44e9-b755-2e7e7bd1d45b', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleanse_area', 'Bölge Arındırma', 'Cleanse Area', '20m yarıçapında bir alanı arındırır. Doğal olmayan sisi, kara büyü yüzeylerini yok eder ve ölümsüzlere 6d6 parlak hasar verir.', 'Purifies a 20m radius. Destroys unnatural fog, dark magic surfaces, and deals 6d6 radiant damage to undead.', 'Purification', 61, 600, 4, '{"pr_aura_of_purity"}', '{"x": 1574, "y": 1876}', '{"radius": "20m", "damage": "6d6"}', '🏞️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('523aa790-2f3b-4bc1-990d-c653080a56a5', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_banishment', 'Sürgün', 'Banishment', '15m içindeki bir yaratığı başka bir varoluş düzlemine göndermeye çalışır. Hedef bir Karizma kurtarma zarında başarılı olamazsa 1 dakika boyunca sürgün edilir.', 'Attempts to send one creature within 15m to another plane of existence. The target must succeed on a Charisma saving throw or be banished for 1 minute.', 'Purification', 65, 700, 4, '{"pr_cleanse_area"}', '{"x": 1735, "y": 2068}', '{"range": "15m", "duration": "1 min"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('524c5e83-2fd6-4772-a570-df2196d16bb2', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_holy_word', 'Kutsal Kelam', 'Holy Word', 'Kutsal bir kelam söyleyin. 10m içindeki gökseller, elementaller, periler, iblisler ve ölümsüzler 5d8 parlak hasar alır ve sağır veya kör olurlar.', 'Utter a divine word. Celestials, elementals, fey, fiends, and undead within 10m suffer 5d8 radiant damage and are deafened or blinded.', 'Purification', 70, 800, 4, '{"pr_banishment"}', '{"x": 1896, "y": 2259}', '{"radius": "10m", "damage": "5d8"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11669833-ecd4-4ca3-9a20-35ed4add0e61', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_globe_of_invulnerability', 'Yenilmezlik Küresi', 'Globe of Invulnerability', 'Etrafınızda hareketsiz, hafifçe parlayan 3m yarıçaplı bir bariyer belirir. Bariyerin dışından yapılan 5. aşama veya daha düşük hiçbir büyü içerideki yaratıkları etkileyemez.', 'An immobile, faintly shimmering 3m radius barrier springs into existence around you. Any spell of 5th tier or lower cast from outside the barrier can''t affect creatures within it.', 'Divine Shield', 61, 600, 4, '{"pr_guardian_of_faith"}', '{"x": -1574, "y": 1876}', '{"radius": "3m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('801424cb-3ea4-4825-a068-93ff9071f041', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_wall_of_light', 'Işık Duvarı', 'Wall of Light', '15m uzunluğunda, 3m yüksekliğinde parlak enerjiden bir duvar oluşturur. İçinden geçen ölümsüzler 4d8 hasar alır ve içerdeki müttefikler yarım siper kazanır.', 'Creates a 15m long, 3m high wall of radiant energy. Undead passing through take 4d8 damage, and allies inside gain half-cover.', 'Divine Shield', 65, 700, 4, '{"pr_globe_of_invulnerability"}', '{"x": -1735, "y": 2068}', '{"wall_length": "15m", "damage": "4d8"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4778018e-bd18-4d6b-9232-b4ad8985bfb6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_holy_aura', 'Kutsal Hale', 'Holy Aura', 'Sizden 10m yarıçapında ilahi bir ışık yayılır. Müttefikler tüm kurtarma zarlarında avantaj sağlar ve düşmanların onlara karşı saldırı zarlarında dezavantajı olur.', 'Divine light radiates from you in a 10m radius. Allies have advantage on all saving throws, and enemies have disadvantage on attack rolls against them.', 'Divine Shield', 70, 800, 4, '{"pr_wall_of_light"}', '{"x": -1896, "y": 2259}', '{"radius": "10m"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8bbbb8ce-9b8a-4d82-99d9-bfc22900487c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_hallowed_ground', 'Kutsal Toprak', 'Hallowed Ground', '15m''lik bir alanı 1 dakikalığına kutsar. Müttefikler +3 ZS kazanır ve içeride yapılan tüm lanetler anında iptal edilir.', 'Sanctifies a 15m area for 1 minute. Allies gain +3 AC, and any curses cast inside are immediately nullified.', 'Purification, Divine Shield', 65, 750, 4, '{"pr_cleanse_area", "pr_globe_of_invulnerability"}', '{"x": 389, "y": -224}', '{"radius": "15m", "duration": "1 min", "ac_bonus": "+3"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ea1987d-8b54-44b0-a1a7-c42a170e150f', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_martyrs_grace', 'Şehidin Lütfu', 'Martyr''s Grace', 'Mevcut canınızın %50''sini feda ederek bir müttefikinizin canını tamamen yeniler ve onlara 50 canlık bir kalkan sağlarsınız.', 'Sacrifice 50% of your current HP to restore an ally to full HP and grant them a 50 HP shield.', 'Healing, Divine Shield', 75, 850, 4, '{"pr_resurrection", "pr_holy_aura"}', '{"x": 389, "y": -224}', '{"range": "touch", "shield": "50 hp", "healing": "100%"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b70cd5e6-9dd7-4fc2-80bf-21f3b0ae7610', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_divine_regeneration', 'Kutsal Yenilenme', 'Divine Regeneration', 'Hedef anında 4d8 + 15 can geri kazanır ve 1 dakika boyunca her turunun başında 10 can yeniler. Kopmuş vücut parçaları yeniden büyür.', 'Target regains 4d8 + 15 HP immediately, and regenerates 10 HP at the start of each of their turns for 1 minute. Severed body parts regrow.', 'Healing', 81, 1000, 5, '{"pr_resurrection"}', '{"x": 2771, "y": -1599}', '{"healing": "4d8 + 15", "regen": "10/turn", "duration": "1 min"}', '❤️‍🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('63694a97-cc93-423b-9e96-1c303da02d51', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_healing', 'Tanrıçanın Nefesi', 'Breath of the Goddess', 'ULTİMAT: 30m yarıçapında ilahi bir nefes akar. Tüm müttefikler 100 can iyileşir ve düşmüş tüm müttefikler %50 canla diriltilir. Günde bir kez.', 'ULTIMATE: A divine breath flows through a 30m radius. All allies are healed for 100 HP, and all fallen allies are revived with 50% HP. Once per day.', 'Healing', 90, 1200, 5, '{"pr_divine_regeneration"}', '{"x": 2987, "y": -1724}', '{"radius": "30m", "healing": "100 hp", "revive": "50%"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31deadee-4e15-4556-8318-743d3d44e8bc', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_curse_immunity', 'Lanet Bağışıklığı', 'Curse Immunity', 'Dokunulan bir müttefike 24 saat boyunca tüm lanetlere ve büyülere karşı kalıcı bağışıklık sağlar. Mevcut tüm lanetler paramparça olur.', 'Grants a touched ally permanent immunity to all curses and hexes for 24 hours. Any existing curses are shattered.', 'Purification', 81, 1000, 5, '{"pr_holy_word"}', '{"x": 2056, "y": 2451}', '{"range": "touch", "duration": "24 hours"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48e27b8a-7683-424e-9531-7a85e0de5feb', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_purification', 'Mutlak Arınma Işığı', 'Light of Absolution', 'ULTİMAT: Göklerden kör edici bir ışık sütunu iner (20m yarıçap). Tüm kara büyüleri, lanetleri buharlaştırır ve iblislere ve ölümsüzlere 15d10 parlak hasar verir.', 'ULTIMATE: A blinding pillar of light descends from the heavens (20m radius). Evaporates all dark magic, curses, and deals 15d10 radiant damage to fiends and undead.', 'Purification', 90, 1200, 5, '{"pr_curse_immunity"}', '{"x": 2217, "y": 2642}', '{"radius": "20m", "damage": "15d10"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ca01e6d-bfb9-4ac1-b899-faaa1fbc204e', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aegis_of_the_gods', 'Tanrıların Kalkanı', 'Aegis of the Gods', 'Dışarıdan gelen tüm fiziksel ve büyüsel saldırıları 3 tur boyunca engelleyen delinmez altın bir kubbe (10m yarıçap) çağırır. Hiçbir şey içinden geçemez.', 'Conjures an impenetrable golden dome (10m radius) that blocks all physical and magical attacks from outside for 3 turns. Nothing can pass through.', 'Divine Shield', 81, 1000, 5, '{"pr_holy_aura"}', '{"x": -2056, "y": 2451}', '{"radius": "10m", "duration": "3 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07a34030-b59c-4705-8b46-eb945705b0f3', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_shield', 'Cennetin Kalesi', 'Bastion of Heaven', 'ULTİMAT: En fazla 8 müttefike 2 tur boyunca kırılmaz ilahi bir kalkan sağlar. Kalkanlıyken, alınan hasarın %100''ünü saldırgana geri yansıtırlar.', 'ULTIMATE: Grants up to 8 allies an unbreakable divine shield for 2 turns. While shielded, they reflect 100% of damage taken back to the attacker.', 'Divine Shield', 90, 1200, 5, '{"pr_aegis_of_the_gods"}', '{"x": -2217, "y": 2642}', '{"duration": "2 turns", "reflect": "100%", "targets": "8"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8401d76a-35c4-4f03-9db8-43e2e9a69863', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_avatar_of_mercy', 'Merhamet Avatarı', 'Avatar of Mercy', '1 dakikalığına melek benzeri bir varlığa dönüşün. Uçma hızı kazanırsınız, müttefikleri turda 15 can iyileştiren, zayıflatmaları arındıran ve +5 ZS sağlayan 15m''lik bir hale yayarsınız.', 'Transform into an angelic being for 1 minute. You gain flying speed, emit a 15m aura that heals allies 15 HP/turn, purifies debuffs, and grants +5 AC.', 'Healing, Purification, Divine Shield', 85, 1100, 5, '{"pr_divine_regeneration", "pr_curse_immunity", "pr_aegis_of_the_gods"}', '{"x": 173, "y": -99}', '{"radius": "15m", "healing": "15/turn", "ac_bonus": "+5", "duration": "1 min"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5ea2eb5-5d00-4984-9c01-7847be46513b', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_grand_ultimate', 'İlahi Mucize', 'Miracle of the Divine', 'BÜYÜK ULTİMAT: İlahi ışık savaş alanını yıkarken zaman durur. Tüm müttefikleri tamamen iyileştirir, arındırır, diriltir ve onlara 3 tur boyunca yenilmezlik sağlar. Maksimum canınızın %50''sine mal olur.', 'GRAND ULTIMATE: Time stops as divine light washes over the battlefield. Fully heals, purifies, and revives all allies, and grants them invulnerability for 3 turns. Costs 50% of your maximum HP.', 'Healing, Purification, Divine Shield', 100, 1500, 5, '{"pr_ultimate_healing", "pr_ultimate_purification", "pr_ultimate_shield"}', '{"x": 389, "y": -224}', '{"healing": "100%", "duration": "3 turns"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('713d2ebb-73c6-4183-b69d-cfb7d7f4c9cf', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_minor_telepathy', 'Küçük Telepati', 'Minor Telepathy', 'Bir yaratıkla küçük bir zihinsel bağ kurarak temel iletişim sağlar.', 'Establish a minor mental link with a creature, allowing basic communication.', 'Telepathy', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "30m", "duration": "10m"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48d7b7f1-9fc1-4ca4-adf2-c4e320af17a6', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_kinetic_push', 'Kinetik İtiş', 'Kinetic Push', 'Bir hedefi uzağa itmek için kinetik enerji patlaması yayar.', 'Emit a burst of kinetic energy to push a target away.', 'Telekinesis', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "range": "15m", "push": "5m"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a0313fe-6827-42e2-acde-89cd5d00b6c8', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_mental_barrier', 'Zihinsel Bariyer', 'Mental Barrier', 'Küçük hasarları emen temel bir zihinsel bariyer oluşturur.', 'Form a basic mental barrier that absorbs minor damage.', 'Psychic Shield', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"temporary_hp": "15", "duration": "1h"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('745f2540-e704-4f74-954f-b7a90d40f414', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_mind_spike', 'Zihin Dikeni', 'Mind Spike', 'Bir hedefin zihnini psişik enerjiyle delerek hasar verir.', 'Pierce a target''s mind with psychic energy, dealing damage.', 'Telepathy', 5, 90, 1, '{"pm_minor_telepathy"}', '{"x": 389, "y": -224}', '{"damage": "2d6", "range": "20m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45a1c9ab-1142-4117-9159-be0f28086798', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_levitation', 'Levitasyon', 'Levitation', 'Kendinizi veya hafif bir nesneyi havaya kaldırırsınız.', 'Lift yourself or a light object into the air.', 'Telekinesis', 6, 100, 1, '{"pm_kinetic_push"}', '{"x": 289, "y": 344}', '{"height": "10m", "duration": "5m"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b8160d4-1126-4d28-8d95-a29e012b6f33', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_force_ward', 'Güç Kalkanı', 'Force Ward', 'Bir müttefiki gelen hasarı azaltan bir koruma ile çevreler.', 'Surround an ally with a ward that reduces incoming damage.', 'Psychic Shield', 7, 110, 1, '{"pm_mental_barrier"}', '{"x": -289, "y": 344}', '{"damage_reduction": "3", "duration": "10m"}', '🔰');
